// Parse filename to extract metadata
const filename = $input.first().json.name;

// Expected format: script_{script_id}_idea_{idea_id}_hook_{hook_id}_transcript_{transcript_id}_source_{source_id}.mp4

const regex = /script_([^_]+)_idea_([^_]+)_hook_([^_]+)_transcript_([^_]+)_source_([^_]+)\.mp4/;
const match = filename.match(regex);

if (!match) {
  throw new Error(`Invalid filename format: ${filename}. Expected: script_ID_idea_ID_hook_ID_transcript_ID_source_ID.mp4`);
}

return {
  file_id: $input.first().json.id,
  filename: filename,
  drive_url: $input.first().json.webViewLink,

  // Extracted metadata
  script_id: match[1],
  idea_id: match[2],
  hook_variant_id: match[3] === 'null' ? null : match[3],
  transcript_id: match[4],
  source_reel_id: match[5] === 'null' ? null : match[5]
};

// Generate caption for Instagram/TikTok
const hookText = $('Get Full Context from DB').item.json.hook_text || '';
const niche = $('Get Full Context from DB').item.json.niche || '';

// Get relevant hashtags based on niche
const hashtagMap = {
  'fitness': '#fitness #workout #gym #health #fitnessmotivation',
  'tech': '#tech #technology #ai #innovation #startup',
  'finance': '#finance #money #investing #wealth #business',
  'education': '#education #learning #knowledge #study #tips',
  'entertainment': '#entertainment #funny #viral #trending #fyp'
};

const hashtags = hashtagMap[niche] || '#viral #trending #fyp';

// Build caption
const caption = `${hookText}

${hashtags}

💾 Save this for later
👉 Follow for more`;

return {
  caption: caption,
  hook_text: hookText,
  niche: niche
};
